#include <stdio.h>
int main() {
    int T, N, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            int or = 0;
            for (int j = i; j < N; j++) {
                or |= A[j];
                if (or >= K) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

